def get_cell_umi_read_string(read_id, sep='_'):
    if isinstance(read_id, bytes):
        read_id = read_id.decode('utf-8')
    parts = read_id.rsplit(sep, maxsplit=2)
    if len(parts) < 3:
        raise ValueError('Read ID must contain at least two separators')
    p0, p1, p2 = parts
    # Determine UMI field
    if p2.startswith('UMI'):
        # Normal case: last part is the full UMI
        umi_field = p2
        cb_field = p1
    else:
        # UMI spans last two parts (p1 starts with UMI)
        if not p1.startswith('UMI'):
            raise ValueError('Invalid UMI: ' + p1)
        umi_field = p1 + sep + p2
        # Extract CB from p0 (last occurrence of 'CB' to end)
        idx = p0.rfind('CB')
        if idx == -1:
            raise ValueError('Invalid cell barcode: ' + p0)
        cb_field = p0[idx:]
    # Validate UMI: must start with 'UMI', remainder only A,C,G,T,_
    if not umi_field.startswith('UMI'):
        raise ValueError('Invalid UMI: ' + umi_field)
    umi_remainder = umi_field[3:]
    if not all(c in 'ACGT_' for c in umi_remainder):
        raise ValueError('Invalid UMI: ' + umi_field)
    # Validate CB: must start with 'CB'
    if not cb_field.startswith('CB'):
        raise ValueError('Invalid cell barcode: ' + cb_field)
    return umi_field.encode('utf-8'), cb_field.encode('utf-8')
